  class TrieNode:
      def __init__(self):
          self.children = {}
          self.is_end = False

Step 2: Build the trie by inserting each word.
  def trie_search(words, prefix):
      root = TrieNode()
      for word in words:
          node = root
          for ch in word:
              if ch not in node.children:
                  node.children[ch] = TrieNode()
              node = node.children[ch]
          node.is_end = True

Step 3: Navigate to the prefix node.
      node = root
      for ch in prefix:
          if ch not in node.children:
              return []
          node = node.children[ch]

Step 4: Collect all words under the prefix node using DFS.
      results = []
      def dfs(node, path):
          if node.is_end:
              results.append(prefix + path)
          for c, child in node.children.items():
              dfs(child, path + c)
      dfs(node, '')
      return results

